{"path":"apps/web/src/components/CreateRunForm.tsx","content":"import { useState } from 'react';

export default function CreateRunForm({ onCreated }: { onCreated: () => void }) {
  const [repoUrl, setRepoUrl] = useState('');
  const [baseBranch, setBaseBranch] = useState('main');
  const [prompt, setPrompt] = useState('');
  const [agent, setAgent] = useState('mock-agent');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const res = await fetch('/api/runs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ repoUrl, baseBranch, prompt, agent }),
      });
      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || 'Failed to create run');
      }
      setRepoUrl('');
      setPrompt('');
      onCreated();
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err));
    } finally {
      setLoading(false);
    }
  }

  return (
    <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: 12, marginBottom: 24 }}>
      <h2>Create Run</h2>
      {error && <div style={{ color: '#ef4444' }}>{error}</div>}
      <input
        placeholder="Repo URL"
        value={repoUrl}
        onChange={(e) => setRepoUrl(e.target.value)}
        required
        style={{ padding: 8, borderRadius: 4, border: '1px solid #d1d5db' }}
      />
      <input
        placeholder="Base Branch"
        value={baseBranch}
        onChange={(e) => setBaseBranch(e.target.value)}
        required
        style={{ padding: 8, borderRadius: 4, border: '1px solid #d1d5db' }}
      />
      <textarea
        placeholder="Prompt"
        value={prompt}
        onChange={(e) => setPrompt(e.target.value)}
        required
        rows={3}
        style={{ padding: 8, borderRadius: 4, border: '1px solid #d1d5db' }}
      />
      <input
        placeholder="Agent"
        value={agent}
        onChange={(e) => setAgent(e.target.value)}
        required
        style={{ padding: 8, borderRadius: 4, border: '1px solid #d1d5db' }}
      />
      <button
        type="submit"
        disabled={loading}
        style={{
          padding: '10px 16px',
          borderRadius: 4,
          border: 'none',
          backgroundColor: '#3b82f6',
          color: '#fff',
          cursor: loading ? 'not-allowed' : 'pointer',
          opacity: loading ? 0.6 : 1,
        }}
      >
        {loading ? 'Creating...' : 'Create Run'}
      </button>
    </form>
  );
}
"}

