{"path":"apps/web/src/components/LogPanel.tsx","content":"import { useEffect, useRef, useState } from 'react';
import type { RunLog } from '@repopilot/shared';

export default function LogPanel({ runId }: { runId: number }) {
  const [logs, setLogs] = useState<RunLog[]>([]);
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    let eventSource: EventSource | null = null;

    async function init() {
      // Fetch historical logs first
      const res = await fetch(`/api/runs/${runId}/logs`);
      if (res.ok) {
        const data = await res.json();
        setLogs(data);
      }

      // Then subscribe to live logs
      eventSource = new EventSource(`/api/runs/${runId}/logs`);
      eventSource.onmessage = (event) => {
        const log: RunLog = JSON.parse(event.data);
        setLogs((prev) => [...prev, log]);
      };
    }

    init();

    return () => {
      if (eventSource) eventSource.close();
    };
  }, [runId]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  return (
    <div
      style={{
        backgroundColor: '#111827',
        color: '#e5e7eb',
        padding: 16,
        borderRadius: 8,
        fontFamily: 'monospace',
        fontSize: 13,
        maxHeight: 400,
        overflowY: 'auto',
      }}
    >
      {logs.map((log) => (
        <div key={log.id} style={{ marginBottom: 4 }}>
          <span style={{ color: log.level === 'error' ? '#ef4444' : log.level === 'warn' ? '#f59e0b' : '#10b981' }}>
            [{log.level.toUpperCase()}]
          </span>{' '}
          {log.message}
        </div>
      ))}
      <div ref={bottomRef} />
    </div>
  );
}
"}

{"path":"apps/web/src/components/DiffViewer.tsx","content":"import { useEffect, useState } from 'react';

interface DiffFile {
  path: string;
  additions: number;
  deletions: number;
  patch: string;
}

export default function DiffViewer({ runId }: { runId: number }) {
  const [files, setFiles] = useState<DiffFile[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    async function load() {
      try {
        const res = await fetch(`/api/runs/${runId}/diff`);
        if (!res.ok) {
          const data = await res.json();
          throw new Error(data.error || 'Failed to load diff');
        }
        const data = await res.json();
        setFiles(data.files);
      } catch (err) {
        setError(err instanceof Error ? err.message : String(err));
      } finally {
        setLoading(false);
      }
    }
    load();
  }, [runId]);

  if (loading) return <p>Loading diff...</p>;
  if (error) return <p style={{ color: '#ef4444' }}>{error}</p>;
  if (files.length === 0) return <p>No diff available.</p>;

  return (
    <div>
      {files.map((file) => (
        <div key={file.path} style={{ marginBottom: 24, border: '1px solid #e5e7eb', borderRadius: 8, overflow: 'hidden' }}>
          <div style={{ backgroundColor: '#f3f4f6', padding: '8px 12px', fontWeight: 600, fontSize: 14 }}>
            {file.path}{' '}
            <span style={{ color: '#10b981' }}>+{file.additions}</span>{' '}
            <span style={{ color: '#ef4444' }}>-{file.deletions}</span>
          </div>
          <pre
            style={{
              margin: 0,
              padding: 12,
              fontSize: 12,
              overflowX: 'auto',
              backgroundColor: '#fff',
            }}
          >
            {file.patch}
          </pre>
        </div>
      ))}
    </div>
  );
}
"}

