{"path":"apps/web/src/pages/RunDetailPage.tsx","content":"import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import StatusBadge from '../components/StatusBadge.js';
import LogPanel from '../components/LogPanel.js';
import DiffViewer from '../components/DiffViewer.js';
import type { Run } from '@repopilot/shared';

export default function RunDetailPage() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [run, setRun] = useState<Run | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [rejectFeedback, setRejectFeedback] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  async function loadRun() {
    try {
      const res = await fetch(`/api/runs/${id}`);
      if (!res.ok) throw new Error('Run not found');
      const data = await res.json();
      setRun(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err));
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    loadRun();
    const interval = setInterval(loadRun, 3000);
    return () => clearInterval(interval);
  }, [id]);

  async function handleApprove() {
    setActionLoading(true);
    try {
      const res = await fetch(`/api/runs/${id}/approve`, { method: 'POST' });
      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || 'Failed to approve');
      }
      loadRun();
    } catch (err) {
      alert(err instanceof Error ? err.message : String(err));
    } finally {
      setActionLoading(false);
    }
  }

  async function handleReject() {
    if (!rejectFeedback.trim()) {
      alert('Please provide feedback');
      return;
    }
    setActionLoading(true);
    try {
      const res = await fetch(`/api/runs/${id}/reject`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ feedback: rejectFeedback }),
      });
      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || 'Failed to reject');
      }
      loadRun();
    } catch (err) {
      alert(err instanceof Error ? err.message : String(err));
    } finally {
      setActionLoading(false);
    }
  }

  if (loading) return <p>Loading...</p>;
  if (error) return <p style={{ color: '#ef4444' }}>{error}</p>;
  if (!run) return <p>Run not found</p>;

  const canApprove = run.status === 'completed';
  const canReject = run.status === 'completed' || run.status === 'failed';

  return (
    <div>
      <button onClick={() => navigate('/')} style={{ marginBottom: 16 }}>
        &larr; Back
      </button>

      <h2>Run #{run.id}</h2>
      <div style={{ marginBottom: 16 }}>
        <StatusBadge status={run.status} />
      </div>

      <div style={{ display: 'grid', gap: 12, marginBottom: 24 }}>
        <div>
          <strong>Repo:</strong> {run.repoUrl}
        </div>
        <div>
          <strong>Base Branch:</strong> {run.baseBranch}
        </div>
        <div>
          <strong>Agent Branch:</strong> {run.branchName}
        </div>
        <div>
          <strong>Agent:</strong> {run.agent}
        </div>
        <div>
          <strong>Prompt:</strong> {run.prompt}
        </div>
        {run.errorMessage && (
          <div style={{ color: '#ef4444' }}>
            <strong>Error:</strong> {run.errorMessage}
          </div>
        )}
        {run.approvedAt && (
          <div>
            <strong>Approved:</strong> {new Date(run.approvedAt).toLocaleString()}
          </div>
        )}
        {run.rejectedAt && (
          <div>
            <strong>Rejected:</strong> {new Date(run.rejectedAt).toLocaleString()}
            {run.rejectionFeedback && <div><strong>Feedback:</strong> {run.rejectionFeedback}</div>}
          </div>
        )}
      </div>

      {(canApprove || canReject) && (
        <div style={{ display: 'flex', gap: 12, marginBottom: 24, alignItems: 'flex-start' }}>
          {canApprove && (
            <button
              onClick={handleApprove}
              disabled={actionLoading}
              style={{
                padding: '10px 20px',
                backgroundColor: '#10b981',
                color: '#fff',
                border: 'none',
                borderRadius: 4,
                cursor: actionLoading ? 'not-allowed' : 'pointer',
              }}
            >
              Approve
            </button>
          )}
          {canReject && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              <textarea
                placeholder="Rejection feedback"
                value={rejectFeedback}
                onChange={(e) => setRejectFeedback(e.target.value)}
                rows={2}
                style={{ padding: 8, borderRadius: 4, border: '1px solid #d1d5db', minWidth: 300 }}
              />
              <button
                onClick={handleReject}
                disabled={actionLoading}
                style={{
                  padding: '10px 20px',
                  backgroundColor: '#ef4444',
                  color: '#fff',
                  border: 'none',
                  borderRadius: 4,
                  cursor: actionLoading ? 'not-allowed' : 'pointer',
                }}
              >
                Reject
              </button>
            </div>
          )}
        </div>
      )}

      <h3>Logs</h3>
      <LogPanel runId={run.id} />

      <h3 style={{ marginTop: 24 }}>Diff</h3>
      <DiffViewer runId={run.id} />
    </div>
  );
}
"}

{"path":"apps/api/src/services/runService.test.ts","content":"import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import fs from 'fs/promises';
import path from 'path';
import { simpleGit } from 'simple-git';
import { db } from '../db/index.js';
import { runs, runLogs } from '../db/schema.js';
import { eq } from 'drizzle-orm';
import { createRun, getRuns, getRunById, getRunLogs, getDiff, approveRun, rejectRun } from './runService.js';

let tempDir: string;
let remoteRepo: string;

async function setupRemoteRepo() {
  tempDir = await fs.mkdtemp('/tmp/repopilot-test-');
  remoteRepo = path.join(tempDir, 'remote.git');
  await fs.mkdir(remoteRepo, { recursive: true });
  const git = simpleGit(remoteRepo);
  await git.init(['--bare']);

  // Create a working copy to push initial commit
  const workDir = path.join(tempDir, 'work');
  await fs.mkdir(workDir);
  const workGit = simpleGit(workDir);
  await workGit.init();
  await workGit.addConfig('user.email', 'test@test.com');
  await workGit.addConfig('user.name', 'Test');
  await fs.writeFile(path.join(workDir, 'README.md'), '# Test');
  await workGit.add('README.md');
  await workGit.commit('Initial commit');
  await workGit.addRemote('origin', remoteRepo);
  await workGit.push('origin', 'main');
}

async function cleanup() {
  await fs.rm(tempDir, { recursive: true, force: true });
  // Clean up database
  db.delete(runLogs).run();
  db.delete(runs).run();
}

describe('runService', () => {
  beforeEach(async () => {
    await setupRemoteRepo();
  });

  afterEach(async () => {
    await cleanup();
  });

  it('creates a run and clones repo', async () => {
    const run = await createRun({
      repoUrl: remoteRepo,
      baseBranch: 'main',
      prompt: 'Test prompt',
      agent: 'mock-agent',
    });

    expect(run.id).toBeDefined();
    expect(run.status).toBe('queued');
    expect(run.workspacePath).toContain(`run-${run.id}`);

    // Wait for background job
    await new Promise((r) => setTimeout(r, 2000));

    const updated = getRunById(run.id);
    expect(updated?.status).toBe('completed');
  }, 10000);

  it('returns all runs', async () => {
    await createRun({ repoUrl: remoteRepo, baseBranch: 'main', prompt: 'P1', agent: 'a1' });
    await createRun({ repoUrl: remoteRepo, baseBranch: 'main', prompt: 'P2', agent: 'a2' });

    const all = getRuns();
    expect(all.length).toBe(2);
  });

  it('returns run by id', async () => {
    const run = await createRun({ repoUrl: remoteRepo, baseBranch: 'main', prompt: 'P1', agent: 'a1' });
    const found = getRunById(run.id);
    expect(found?.id).toBe(run.id);
    expect(getRunById(99999)).toBeUndefined();
  });

  it('returns logs for a run', async () => {
    const run = await createRun({ repoUrl: remoteRepo, baseBranch: 'main', prompt: 'P1', agent: 'a1' });
    await new Promise((r) => setTimeout(r, 2000));
    const logs = getRunLogs(run.id);
    expect(logs.length).toBeGreaterThan(0);
  }, 10000);

  it('returns diff for completed run', async () => {
    const run = await createRun({ repoUrl: remoteRepo, baseBranch: 'main', prompt: 'P1', agent: 'a1' });
    await new Promise((r) => setTimeout(r, 2000));
    const result = await getDiff(run.id);
    expect('files' in result).toBe(true);
    if ('files' in result) {
      expect(result.files.length).toBeGreaterThan(0);
    }
  }, 10000);

  it('blocks approving failed run', async () => {
    const run = await createRun({ repoUrl: remoteRepo, baseBranch: 'main', prompt: 'P1', agent: 'a1' });
    db.update(runs).set({ status: 'failed' }).where(eq(runs.id, run.id)).run();
    const result = approveRun(run.id);
    expect(result.success).toBe(false);
    expect(result.error).toContain('failed');
  });

  it('allows rejecting completed run', async () => {
    const run = await createRun({ repoUrl: remoteRepo, baseBranch: 'main', prompt: 'P1', agent: 'a1' });
    db.update(runs).set({ status: 'completed' }).where(eq(runs.id, run.id)).run();
    const result = rejectRun(run.id, 'Too generic');
    expect(result.success).toBe(true);
    const updated = getRunById(run.id);
    expect(updated?.status).toBe('rejected');
    expect(updated?.rejectionFeedback).toBe('Too generic');
  });

  it('blocks rejecting approved run', async () => {
    const run = await createRun({ repoUrl: remoteRepo, baseBranch: 'main', prompt: 'P1', agent: 'a1' });
    db.update(runs).set({ status: 'approved' }).where(eq(runs.id, run.id)).run();
    const result = rejectRun(run.id, 'feedback');
    expect(result.success).toBe(false);
  });

  it('blocks approving rejected run', async () => {
    const run = await createRun({ repoUrl: remoteRepo, baseBranch: 'main', prompt: 'P1', agent: 'a1' });
    db.update(runs).set({ status: 'rejected' }).where(eq(runs.id, run.id)).run();
    const result = approveRun(run.id);
    expect(result.success).toBe(false);
  });
});
"}

