import fs from 'fs/promises';
import path from 'path';
import { simpleGit } from 'simple-git';
import { MockRunner } from './runner.js';
import type { Run } from '@repopilot/shared';

let tempDir: string;
let repoPath: string;

async function setupRepo() {
