  await git.addConfig('user.name', 'Test');
  await fs.writeFile(path.join(repoPath, 'README.md'), '# Test');
  await git.add('README.md');
  await git.commit('Initial commit');
}

async function cleanup() {
  await fs.rm(tempDir, { recursive: true, force: true });
}

describe('MockRunner', () => {
  beforeEach(async () => {
    await setupRepo();
  });

  afterEach(async () => {
    await cleanup();
  });

  it('creates AGENT_RUN.md and commits', async () => {
    const runner = new MockRunner();
    const run: Run = {
      id: 1,
      repoUrl: 'https://github.com/test/repo.git',
      baseBranch: 'main',
      branchName: 'agent/run-1',
      prompt: 'Add health check',
      agent: 'mock-agent',
      status: 'running',
      workspacePath: repoPath,
      errorMessage: null,
      approvedAt: null,
      rejectedAt: null,
      rejectionFeedback: null,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    const logs: Array<{ level: string; message: string }> = [];
    let finalStatus = '';

    await runner.execute(run, {
      onLog: async (log) => {
        logs.push({ level: log.level, message: log.message });
      },
      onStatusChange: async (status) => {
        finalStatus = status;
      },
    });

    expect(finalStatus).toBe('completed');
    expect(logs.some((l) => l.message.includes('File changed'))).toBe(true);
    expect(logs.some((l) => l.message.includes('Commit created'))).toBe(true);

    const content = await fs.readFile(path.join(repoPath, 'AGENT_RUN.md'), 'utf-8');
    expect(content).toContain('Add health check');
    expect(content).toContain('mock-agent');
  });
});
